module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

reg [7:0] mul_a_ext, mul_b_ext;
reg [7:0] partial_product[size-1:0];
reg [7:0] add_reg[size-1:0];
reg [7:0] sum_tmp1, sum_tmp2;

integer i;

assign mul_a_ext = {4'b0000, mul_a};
assign mul_b_ext = {4'b0000, mul_b};

genvar j;
generate
    for(j = 0; j < size; j=j+1) begin : pp_gen
        assign partial_product[j] = (mul_b_ext[j]) ? (mul_a_ext << j) : 'd0;
    end
endgenerate

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        for(i = 0; i < size; i=i+1) begin
            add_reg[i] <= 8'd0;
        end
        sum_tmp1 <= 8'd0;
        sum_tmp2 <= 8'd0;
    end else begin
        add_reg[0] <= partial_product[0];
        add_reg[1] <= add_reg[0] + partial_product[1];
        add_reg[2] <= add_reg[1] + partial_product[2];
        add_reg[3] <= add_reg[2] + partial_product[3];
        sum_tmp1 <= (mul_b_ext[0] ? mul_a_ext : 0) + (mul_b_ext[1] ? mul_a_ext << 1 : 0);
        sum_tmp2 <= (mul_b_ext[2] ? mul_a_ext << 2 : 0) + (mul_b_ext[3] ? mul_a_ext << 3 : 0);
    end
end

always @(posedge clk or negedge rst_n) begin
    if(!rst_n) begin
        mul_out <= 16'd0;
    end else begin
        mul_out <= sum_tmp1 + sum_tmp2;
    end
end

endmodule
